(() => {
  const questions = [
    {id:'argent-profiter-vie',category:'categorie-argent',title:"Il faut gagner beaucoup d’argent pour pouvoir profiter de la vie. Êtes-vous d’accord avec cette affirmation ? Pourquoi ?",p:[
      "Si je comprends bien, il s'agit de savoir s'il faut gagner beaucoup d'argent pour pouvoir profiter de la vie.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que l'argent présente de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, l'argent constitue un véritable atout, car cela permet de répondre à ses besoins essentiels et de préparer l'avenir. En effet, cela favorise également une certaine stabilité financière et une vie plus sereine.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient qu'une situation financière stable réduisait leurs inquiétudes quotidiennes. Cela montre que l'argent contribue à la qualité de vie.",
      "Ensuite, les relations humaines jouent également un rôle essentiel dans le bonheur. Autrement dit, elles contribuent à construire des liens solides, à recevoir du soutien et à avancer avec davantage de sérénité.",
      "Prenons mon propre exemple. Lorsque je prépare le TCF Canada, mon mari m'encourage toujours lorsque je manque de motivation. Son soutien m'aide à progresser et me rend heureuse, sans dépendre d'une dépense importante.",
      "Toutefois, j'aimerais ajouter un dernier point concernant l'argent. Même si l'argent offre de réels avantages, il ne constitue pas le seul facteur à prendre en compte. En effet, la santé, la famille et l'équilibre personnel peuvent également jouer un rôle essentiel.",
      "Prenons l'exemple de mon père. Lorsqu'il est malade, il consulte son médecin et suit son traitement. On voit donc que profiter de la vie dépend aussi de la santé et du bien-être, et pas seulement de la quantité d'argent gagnée.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'internet-travail',category:'categorie-technologie',title:"Internet a changé les comportements au travail. Qu’en pensez-vous ?",p:[
      "Si je comprends bien, il s'agit de savoir comment Internet a changé les comportements au travail.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien qu'Internet présente de nombreux avantages, il est également essentiel de ne pas négliger les risques liés à Internet. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, Internet constitue un véritable atout, car cela permet d'accéder rapidement aux informations et de communiquer à distance. En effet, cela favorise également l'autonomie et une organisation plus souple du travail.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées utilisaient Internet quotidiennement dans leur activité professionnelle. Cela montre qu'Internet est devenu un outil essentiel au travail.",
      "Ensuite, les outils numériques jouent également un rôle essentiel dans la collaboration. Autrement dit, ils contribuent à partager des documents, à travailler avec des collègues éloignés et à apprendre de nouvelles méthodes.",
      "Prenons le cas de mon ami Paul. Grâce à sa capacité d'apprentissage et à ses compétences techniques, il s'adapte rapidement aux nouvelles méthodes de travail. Cet exemple prouve que les outils numériques peuvent favoriser l'évolution professionnelle.",
      "Toutefois, j'aimerais ajouter un dernier point concernant Internet. Même si ce sujet offre de réels avantages, il ne convient pas pour autant de négliger ses limites. En effet, Internet peut comporter certains risques pour la concentration, les relations humaines et l'équilibre entre le travail et la vie personnelle.",
      "Prenons le cas de certaines personnes qui restent connectées après leur journée de travail. Elles ont parfois plus de difficultés à se reposer. On voit donc qu'Internet doit être utilisé de manière raisonnable dans le monde professionnel.",
      "En définitive, il serait réducteur de ne retenir que les aspects positifs ou négatifs de cette question. Il s'agit avant tout d'en tirer le meilleur parti tout en limitant ses éventuels inconvénients."
    ]},
    {id:'media-information',category:'categorie-technologie',title:"Parmi ces médias, lequel préférez-vous pour vous informer ? Expliquez votre choix.",p:[
      "Si je comprends bien, il s'agit de choisir le média que je préfère pour m'informer.",
      "Il serait intéressant de réfléchir à cette question. Si je devais en retenir un, je choisirais Internet. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, Internet constitue un véritable atout, car cela permet d'accéder rapidement à une grande variété d'informations. En effet, cela favorise également la comparaison de plusieurs points de vue.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées utilisaient Internet pour suivre l'actualité. Cela montre que ce média occupe une place importante dans notre vie quotidienne.",
      "Ensuite, la diversité des contenus joue également un rôle essentiel dans mon choix. Autrement dit, elle contribue à consulter des journaux, à écouter la radio ou à regarder des reportages sur un même support.",
      "Prenons mon propre exemple. Lorsque je cherche une information sur le Canada ou sur l'apprentissage du français, je peux lire plusieurs articles et regarder une vidéo explicative. Cet exemple prouve qu'Internet répond facilement à différents besoins.",
      "Toutefois, j'aimerais ajouter un dernier point concernant Internet. Même si ce sujet offre de réels avantages, il ne convient pas pour autant de négliger ses limites. En effet, Internet peut comporter certains risques liés aux informations fausses ou incomplètes.",
      "Prenons le cas de certaines personnes qui partagent une information sans vérifier sa source. On voit donc qu'il est essentiel de comparer plusieurs médias et de privilégier des sources fiables.",
      "En définitive, ce choix correspond pleinement à mes centres d'intérêt, à mon expérience et à mes objectifs. Il s'agit avant tout de poursuivre un projet qui me permette de continuer à apprendre et à progresser."
    ]},
    {id:'relations-habitants',category:'categorie-societe',title:"Pour bien vivre dans un pays étranger, il est indispensable de créer des relations avec les habitants du pays. Qu’en pensez-vous ?",p:[
      "Si je comprends bien, il s'agit de savoir s'il est indispensable de créer des relations avec les habitants pour bien vivre dans un pays étranger.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que les relations avec les habitants présentent de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, les relations avec les habitants constituent un véritable atout, car cela permet de mieux comprendre la culture locale. En effet, cela favorise également la communication, l'entraide et l'intégration.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que les contacts avec les habitants facilitaient l'intégration. Cela montre que les relations humaines sont importantes dans un pays étranger.",
      "Ensuite, la participation à la vie locale joue également un rôle essentiel dans la création de liens. Autrement dit, elle contribue à rencontrer des personnes d'horizons variés et à développer progressivement son réseau social.",
      "Prenons mon propre exemple. Depuis mon arrivée au Canada, je participe à des activités organisées dans la communauté. Cela me permet de rencontrer de nouvelles personnes et de mieux m'intégrer.",
      "Toutefois, j'aimerais ajouter un dernier point concernant l'intégration. Même si les relations avec les habitants offrent de réels avantages, elles ne constituent pas le seul facteur à prendre en compte. En effet, la maîtrise de la langue, la motivation et la compréhension de la culture locale peuvent également jouer un rôle essentiel.",
      "Prenons mon propre exemple. J'apprends le français tous les jours afin de communiquer plus facilement avec les autres. On voit donc que les relations avec les habitants deviennent plus faciles lorsqu'elles sont accompagnées d'efforts personnels.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'langue-enfants-etranger',category:'categorie-famille',title:"À l’étranger avec ses enfants, faut-il leur parler dans la langue du pays d’accueil ou dans celle du pays d’origine ?",p:[
      "Si je comprends bien, il s'agit de savoir s'il faut parler aux enfants dans la langue du pays d'accueil ou dans celle du pays d'origine.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Pour ma part, je pense que la langue du pays d'accueil et la langue du pays d'origine présentent toutes deux des avantages. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, la langue du pays d'accueil constitue un véritable atout, car cela permet aux enfants de communiquer à l'école et de mieux s'intégrer. En effet, cela favorise également leur autonomie et leur adaptation.",
      "Par exemple, depuis son arrivée au Canada, mon fils apprend le français à l'école et s'habitue rapidement à son nouvel environnement. Cela montre que la langue du pays d'accueil facilite l'intégration.",
      "Ensuite, la langue du pays d'origine joue également un rôle essentiel dans l'identité familiale. Autrement dit, elle contribue à transmettre la culture, les traditions et les liens avec la famille.",
      "Prenons l'exemple de mon fils. À la maison, nous pouvons continuer à utiliser notre langue d'origine afin qu'il communique avec notre famille et comprenne ses racines. Cet exemple prouve que cette langue reste importante.",
      "Toutefois, j'aimerais ajouter un dernier point concernant la langue du pays d'origine. Même si la langue du pays d'accueil offre de réels avantages, cela ne signifie pas que la langue du pays d'origine soit moins importante. En effet, la langue du pays d'origine peut également apporter de nombreux bénéfices.",
      "Prenons le cas des enfants bilingues qui utilisent une langue à l'école et une autre en famille. On voit donc qu'il est possible de favoriser l'intégration tout en conservant la langue d'origine.",
      "En définitive, plutôt que d'opposer la langue du pays d'accueil à la langue du pays d'origine, il me semble plus pertinent de reconnaître qu'elles peuvent se compléter. Il s'agit avant tout de trouver la meilleure manière de les concilier selon les besoins de chacun."
    ]},
    {id:'immigres-pays-accueil',category:'categorie-societe',title:"Les immigrés doivent-ils bien connaître leur pays d’accueil ?",p:[
      "Si je comprends bien, il s'agit de savoir si les immigrés doivent bien connaître leur pays d'accueil.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que la connaissance du pays d'accueil présente de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, la connaissance du pays d'accueil constitue un véritable atout, car cela permet de comprendre les règles, les habitudes et les valeurs locales. En effet, cela favorise également l'autonomie et l'intégration.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que la compréhension de la culture locale facilitait l'intégration. Cela montre qu'il est utile de connaître son pays d'accueil.",
      "Ensuite, la maîtrise de la langue joue également un rôle essentiel dans cette connaissance. Autrement dit, elle contribue à communiquer au quotidien et à participer davantage à la vie locale.",
      "Prenons mon propre exemple. Depuis mon arrivée au Canada, j'apprends le français tous les jours et je participe à des activités dans la communauté. Ces expériences m'aident à mieux comprendre mon environnement.",
      "Toutefois, j'aimerais ajouter un dernier point concernant l'intégration. Même si la connaissance du pays offre de réels avantages, elle ne constitue pas le seul facteur à prendre en compte. En effet, l'ouverture d'esprit, la motivation et les efforts personnels peuvent également jouer un rôle essentiel.",
      "Prenons l'exemple de mon fils. Même si beaucoup de choses étaient nouvelles pour lui, il a fait des efforts pour apprendre et s'est très bien adapté. On voit donc que connaître le pays d'accueil est important, mais que l'intégration demande aussi une participation personnelle.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'metiers-difficiles-salaire',category:'categorie-travail',title:"Les métiers les plus difficiles devraient être les métiers les mieux payés. Qu’en pensez-vous ?",p:[
      "Si je comprends bien, il s'agit de savoir si les métiers les plus difficiles devraient être les mieux payés.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que les métiers difficiles présentent de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, un salaire élevé constitue un véritable atout, car cela permet de reconnaître les efforts, les responsabilités et les risques liés à certains métiers. En effet, cela favorise également la motivation et la stabilité financière.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que les métiers comportant de grandes responsabilités méritaient une meilleure rémunération. Cela montre que le salaire peut reconnaître la difficulté du travail.",
      "Ensuite, les compétences jouent également un rôle essentiel dans la rémunération. Autrement dit, elles contribuent à résoudre des problèmes complexes et à assumer davantage de responsabilités.",
      "Prenons le cas de mon ami Paul. Grâce à ses solides compétences techniques, il s'adapte rapidement aux nouvelles méthodes de travail et évolue dans sa carrière. Cet exemple prouve que les compétences doivent également être prises en compte.",
      "Toutefois, j'aimerais ajouter un dernier point concernant les métiers difficiles. Même si les métiers difficiles offrent de réels avantages, ils ne constituent pas les seuls facteurs à prendre en compte. En effet, les métiers difficiles peuvent s'avérer particulièrement bénéfiques pour les personnes qui souhaitent assumer davantage de responsabilités.",
      "Prenons l'exemple de mon mari. Son travail dans un centre de réadaptation demande des compétences, de la patience et de grandes responsabilités envers les patients. On voit donc qu'une rémunération juste doit tenir compte de plusieurs aspects du métier.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'risques-appareils-electroniques',category:'categorie-technologie',title:"Quels sont les risques liés à l’utilisation quotidienne des appareils électroniques ?",p:[
      "Si je comprends bien, il s'agit de savoir quels sont les risques liés à l'utilisation quotidienne des appareils électroniques.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que les appareils électroniques présentent de nombreux avantages, il est également essentiel de ne pas négliger les risques liés aux appareils électroniques. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, une utilisation limitée constitue un véritable atout, car cela permet de profiter des outils numériques sans y consacrer tout son temps. En effet, cela favorise également une meilleure concentration et un bon équilibre quotidien.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées utilisaient plusieurs appareils électroniques chaque jour. Cela montre que leurs effets concernent une grande partie de la population.",
      "Ensuite, le temps passé devant les écrans joue également un rôle essentiel dans la santé. Autrement dit, il contribue parfois à la fatigue, au manque d'activité physique et aux difficultés de concentration.",
      "Prenons l'exemple de mon fils. S'il regarde trop longtemps des vidéos avant ses devoirs, il met davantage de temps à terminer son travail. Cet exemple prouve qu'une utilisation excessive peut nuire à la concentration.",
      "Toutefois, j'aimerais ajouter un dernier point concernant les appareils électroniques. Même si ce sujet offre de réels avantages, il ne convient pas pour autant de négliger ses limites. En effet, les appareils électroniques peuvent comporter certains risques pour la vie privée, le sommeil et les relations humaines.",
      "Prenons le cas de certaines personnes qui utilisent leur téléphone jusque tard dans la nuit ou partagent trop d'informations personnelles. On voit donc qu'il est important de protéger ses données et de limiter le temps d'écran.",
      "En définitive, il serait réducteur de ne retenir que les aspects positifs ou négatifs de cette question. Il s'agit avant tout d'en tirer le meilleur parti tout en limitant ses éventuels inconvénients."
    ]},
    {id:'animal-domestique',category:'categorie-mode-vie',title:"Pour quelles raisons voudrait-on un animal domestique chez soi ?",p:[
      "Si je comprends bien, il s'agit de savoir pourquoi certaines personnes souhaitent avoir un animal domestique chez elles.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que la présence d'un animal présente de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, un animal domestique constitue un véritable atout, car cela permet d'avoir de la compagnie au quotidien. En effet, cela favorise également le bien-être, l'affection et un sentiment de confiance.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que leur animal leur apportait du réconfort. Cela montre que les animaux peuvent jouer un rôle important dans le bien-être.",
      "Ensuite, la responsabilité joue également un rôle essentiel dans la relation avec un animal. Autrement dit, elle contribue à apprendre à prendre soin d'un autre être vivant et à adopter de bonnes habitudes.",
      "Prenons l'exemple de certaines familles. Les enfants peuvent aider à nourrir l'animal ou à s'occuper de lui. Cet exemple prouve qu'un animal peut développer le sens des responsabilités.",
      "Toutefois, j'aimerais ajouter un dernier point concernant les animaux domestiques. Même si leur présence offre de réels avantages, elle ne constitue pas le seul facteur à prendre en compte. En effet, le temps, le budget, l'espace disponible et les soins nécessaires peuvent également jouer un rôle essentiel.",
      "Prenons le cas de certaines personnes qui travaillent beaucoup et disposent de peu de temps. Elles ne peuvent pas toujours répondre correctement aux besoins d'un animal. On voit donc que cette décision doit être prise de manière responsable.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'agriculture-biologique',category:'categorie-societe',title:"Que pensez-vous du développement de l’agriculture biologique ?",p:[
      "Si je comprends bien, il s'agit de donner mon avis sur le développement de l'agriculture biologique.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que l'agriculture biologique présente de nombreux avantages, il est également essentiel de ne pas négliger les risques liés à l'agriculture biologique. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, l'agriculture biologique constitue un véritable atout, car cela permet de limiter certains produits chimiques. En effet, cela favorise également la protection des sols, de l'eau et de la biodiversité.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que des méthodes agricoles plus responsables protégeaient mieux l'environnement. Cela montre que l'agriculture biologique peut contribuer à un avenir durable.",
      "Ensuite, une alimentation de qualité joue également un rôle essentiel dans la santé. Autrement dit, elle contribue à adopter des habitudes alimentaires équilibrées et adaptées à ses besoins.",
      "Prenons mon propre exemple. Dans ma famille, nous essayons de choisir des légumes et des produits frais lorsque cela est possible. Cet exemple prouve que nos choix alimentaires peuvent soutenir une consommation plus responsable.",
      "Toutefois, j'aimerais ajouter un dernier point concernant l'agriculture biologique. Même si ce sujet offre de réels avantages, il ne convient pas pour autant de négliger ses limites. En effet, les produits biologiques peuvent comporter certains risques liés au prix et à leur accessibilité.",
      "Prenons le cas de certaines familles qui disposent d'un budget limité. Elles ne peuvent pas toujours acheter des produits biologiques plus chers. On voit donc que leur développement doit être accompagné de solutions accessibles à tous.",
      "En définitive, il serait réducteur de ne retenir que les aspects positifs ou négatifs de cette question. Il s'agit avant tout d'en tirer le meilleur parti tout en limitant ses éventuels inconvénients."
    ]},
    {id:'teletravail-equilibre',category:'categorie-travail',title:"Le télétravail permet d’avoir un bon équilibre entre vie professionnelle et vie personnelle. Qu’en pensez-vous ?",p:[
      "Si je comprends bien, il s'agit de savoir si le télétravail permet d'avoir un bon équilibre entre la vie professionnelle et la vie personnelle.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que le télétravail présente de nombreux avantages, il est également essentiel de ne pas négliger les risques liés au télétravail. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, le télétravail constitue un véritable atout, car cela permet de réduire le temps consacré aux déplacements. En effet, cela favorise également une organisation plus souple et davantage de temps pour la famille.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que le télétravail leur permettait de mieux organiser leur journée. Cela montre qu'il peut améliorer l'équilibre quotidien.",
      "Ensuite, l'autonomie joue également un rôle essentiel dans le télétravail. Autrement dit, elle contribue à organiser ses tâches et à travailler dans un environnement plus calme.",
      "Prenons l'exemple de mon mari. Lorsqu'il peut mieux organiser son emploi du temps, il dispose de davantage de temps pour se reposer et pour notre famille. Cet exemple prouve qu'une organisation souple peut favoriser le bien-être.",
      "Toutefois, j'aimerais ajouter un dernier point concernant le télétravail. Même si ce sujet offre de réels avantages, il ne convient pas pour autant de négliger ses limites. En effet, le télétravail peut comporter certains risques pour les relations humaines et la séparation entre le travail et la vie personnelle.",
      "Prenons le cas de certaines personnes qui restent connectées toute la journée à la maison. Elles ont parfois du mal à arrêter de travailler. On voit donc que le télétravail améliore l'équilibre seulement lorsque des limites claires sont respectées.",
      "En définitive, il serait réducteur de ne retenir que les aspects positifs ou négatifs de cette question. Il s'agit avant tout d'en tirer le meilleur parti tout en limitant ses éventuels inconvénients."
    ]},
    {id:'cameras-surveillance',category:'categorie-valeurs',title:"Les caméras de surveillance améliorent-elles la sécurité dans les lieux publics ?",p:[
      "Si je comprends bien, il s'agit de savoir si les caméras de surveillance améliorent la sécurité des citoyens dans les lieux publics.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que les caméras de surveillance présentent de nombreux avantages, il est également essentiel de ne pas négliger les risques liés aux caméras de surveillance. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, les caméras constituent un véritable atout, car cela permet de surveiller certains lieux et d'identifier plus facilement un problème. En effet, cela favorise également un sentiment de sécurité pour les citoyens.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées se sentaient plus rassurées dans certains lieux surveillés. Cela montre que les caméras peuvent contribuer à la sécurité.",
      "Ensuite, l'intervention des services responsables joue également un rôle essentiel dans la sécurité. Autrement dit, elle contribue à réagir rapidement lorsqu'une situation dangereuse est détectée.",
      "Prenons le cas de certains lieux publics très fréquentés. Les images peuvent aider les responsables à comprendre une situation et à intervenir. Cet exemple prouve que la technologie peut soutenir le travail des services de sécurité.",
      "Toutefois, j'aimerais ajouter un dernier point concernant les caméras. Même si ce sujet offre de réels avantages, il ne convient pas pour autant de négliger ses limites. En effet, les caméras peuvent comporter certains risques pour la vie privée et la protection des données.",
      "Prenons le cas de certaines personnes filmées sans savoir comment les images seront utilisées. On voit donc que la surveillance doit être encadrée par des règles claires et ne peut pas remplacer la présence humaine.",
      "En définitive, il serait réducteur de ne retenir que les aspects positifs ou négatifs de cette question. Il s'agit avant tout d'en tirer le meilleur parti tout en limitant ses éventuels inconvénients."
    ]},
    {id:'vetements-vie',category:'categorie-mode-vie',title:"Pensez-vous que le choix des vêtements est important dans la vie ? Expliquez pourquoi.",p:[
      "Si je comprends bien, il s'agit de savoir si le choix des vêtements est important dans la vie.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que le choix des vêtements présente de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, des vêtements adaptés constituent un véritable atout, car cela permet de se sentir à l'aise et de gagner en confiance. En effet, cela favorise également une image soignée dans certaines situations importantes.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que leur tenue influençait leur confiance. Cela montre que les vêtements peuvent avoir un effet sur le bien-être.",
      "Ensuite, le contexte joue également un rôle essentiel dans le choix des vêtements. Autrement dit, il contribue à choisir une tenue adaptée au travail, à une activité ou à la météo.",
      "Prenons mon propre exemple. Lorsque je participe à un entretien ou à une activité importante, je préfère porter des vêtements soignés. Cela me permet d'être plus à l'aise et de communiquer avec davantage de confiance.",
      "Toutefois, j'aimerais ajouter un dernier point concernant les vêtements. Même si leur choix offre de réels avantages, il ne constitue pas le seul facteur à prendre en compte. En effet, la personnalité, les compétences et la confiance en soi peuvent également jouer un rôle essentiel.",
      "Prenons le cas de certaines personnes qui accordent trop d'importance aux marques ou au regard des autres. On voit donc que les vêtements sont utiles, mais qu'ils ne déterminent pas à eux seuls la valeur d'une personne.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'actions-individuelles-environnement',category:'categorie-societe',title:"Les actions de chaque personne sont-elles efficaces pour sauver l’environnement ?",p:[
      "Si je comprends bien, il s'agit de savoir si les actions de chaque personne sont efficaces pour sauver l'environnement.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que les actions individuelles présentent de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, les gestes quotidiens constituent un véritable atout, car cela permet de réduire le gaspillage et la pollution. En effet, cela favorise également des habitudes plus responsables à long terme.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées pratiquaient au moins un geste écologique. Cela montre que chacun peut contribuer au changement.",
      "Ensuite, l'éducation joue également un rôle essentiel dans la protection de l'environnement. Autrement dit, elle contribue à sensibiliser les enfants et à transmettre de bonnes habitudes.",
      "Prenons l'exemple de mon fils. À l'école, il apprend à recycler et à économiser l'énergie. Cet exemple prouve que les comportements responsables peuvent s'apprendre dès le plus jeune âge.",
      "Toutefois, j'aimerais ajouter un dernier point concernant les actions individuelles. Même si elles offrent de réels avantages, elles ne constituent pas le seul facteur à prendre en compte. En effet, les pouvoirs publics et les entreprises peuvent également jouer un rôle essentiel.",
      "Prenons le cas d'une famille qui trie ses déchets alors que les entreprises continuent à utiliser trop d'emballages jetables. On voit donc que les efforts de chacun sont utiles, mais qu'ils doivent être accompagnés par des actions collectives.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'bonheur-travail',category:'categorie-travail',title:"L’essentiel dans la vie est-il de trouver du bonheur au travail ? Qu’en pensez-vous ?",p:[
      "Si je comprends bien, il s'agit de savoir si l'essentiel dans la vie est de trouver du bonheur au travail.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que le bonheur au travail présente de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, le bonheur au travail constitue un véritable atout, car cela permet de rester motivé et de s'épanouir professionnellement. En effet, cela favorise également la concentration, la confiance en soi et la qualité du travail.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient qu'un bon environnement professionnel améliorait leur motivation. Cela montre que le bonheur au travail joue un rôle important.",
      "Ensuite, l'équilibre entre la vie professionnelle et la vie personnelle joue également un rôle essentiel dans le bien-être. Autrement dit, il contribue à limiter le stress et à préserver du temps pour la famille.",
      "Prenons l'exemple de mon mari. Malgré son travail, il accorde toujours du temps à notre famille et m'encourage dans mes études de français. Cet exemple prouve que l'épanouissement dépend aussi d'un bon équilibre quotidien.",
      "Toutefois, j'aimerais ajouter un dernier point concernant le bonheur au travail. Même si le bonheur au travail offre de réels avantages, il ne constitue pas le seul facteur à prendre en compte. En effet, le bonheur au travail peut s'avérer particulièrement bénéfique pour les personnes qui maintiennent aussi de bonnes relations et prennent soin de leur santé.",
      "Prenons mon propre exemple. Le soutien de ma famille, mon apprentissage du français et mes activités personnelles contribuent également à mon bien-être. On voit donc que le bonheur dans la vie ne dépend pas uniquement du travail.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'epanoui-vivre-seul',category:'categorie-famille',title:"Pensez-vous que l’on puisse être épanoui en vivant seul ? Pourquoi ?",p:[
      "Si je comprends bien, il s'agit de savoir s'il est possible d'être épanoui en vivant seul.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que le fait de vivre seul présente de nombreux avantages, il est également essentiel de ne pas négliger les risques liés au fait de vivre seul. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, le fait de vivre seul constitue un véritable atout, car cela permet de devenir plus autonome et d'organiser librement sa vie quotidienne. En effet, cela favorise également la confiance en soi et le développement personnel.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que vivre seul leur avait appris à devenir plus autonomes. Cela montre que cette expérience peut favoriser l'épanouissement.",
      "Ensuite, les relations humaines jouent également un rôle essentiel dans le bien-être. Autrement dit, elles contribuent à recevoir du soutien, à créer des liens solides et à avancer avec davantage de sérénité.",
      "Prenons mon propre exemple. Lorsque je prépare le TCF Canada, mon mari m'encourage lorsque je manque de motivation. Cet exemple prouve que le soutien des autres reste précieux dans les moments difficiles.",
      "Toutefois, j'aimerais ajouter un dernier point concernant le fait de vivre seul. Même si ce sujet offre de réels avantages, il ne convient pas pour autant de négliger ses limites. En effet, le fait de vivre seul peut comporter certains risques pour les relations sociales et le bien-être émotionnel.",
      "Prenons le cas de certaines personnes qui restent souvent seules et participent rarement à la vie locale. Elles peuvent parfois souffrir d'isolement. On voit donc qu'il est possible d'être épanoui en vivant seul à condition de conserver des relations avec les autres.",
      "En définitive, il serait réducteur de ne retenir que les aspects positifs ou négatifs de cette question. Il s'agit avant tout d'en tirer le meilleur parti tout en limitant ses éventuels inconvénients."
    ]},
    {id:'sante-alimentation',category:'categorie-sante',title:"Le plus important pour conserver la santé est-il de bien se nourrir ? Qu’en pensez-vous ?",p:[
      "Si je comprends bien, il s'agit de savoir si le plus important pour conserver la santé est de bien se nourrir.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien qu'une bonne alimentation présente de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, une alimentation équilibrée constitue un véritable atout, car cela permet d'apporter au corps les éléments dont il a besoin. En effet, cela favorise également l'énergie quotidienne et le renforcement du système immunitaire.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient qu'une alimentation équilibrée contribuait à préserver leur santé. Cela montre que la nourriture joue un rôle essentiel.",
      "Ensuite, l'activité physique joue également un rôle essentiel dans la santé. Autrement dit, elle contribue à préserver la mobilité, à réduire le stress et à améliorer le bien-être.",
      "Prenons l'exemple de mon fils. Il joue au tennis avec moi le week-end. Cette activité nous permet de bouger et de passer un bon moment ensemble. Cet exemple prouve que l'exercice complète une bonne alimentation.",
      "Toutefois, j'aimerais ajouter un dernier point concernant l'alimentation. Même si une bonne alimentation offre de réels avantages, elle ne constitue pas le seul facteur à prendre en compte. En effet, une bonne alimentation peut s'avérer particulièrement bénéfique pour les personnes qui prennent également soin de leur santé physique et mentale.",
      "Prenons l'exemple de mon père. Lorsqu'il est malade, il consulte son médecin et suit le traitement prescrit. On voit donc que conserver la santé dépend aussi du suivi médical, du repos et de bonnes habitudes de vie.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'jeune-trouver-emploi',category:'categorie-travail',title:"Selon vous, que doit faire un jeune pour trouver un emploi ?",p:[
      "Si je comprends bien, il s'agit de savoir ce qu'un jeune doit faire pour trouver un emploi.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que la formation présente de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, la formation constitue un véritable atout, car cela permet d'acquérir des connaissances et des compétences utiles. En effet, cela favorise également une meilleure préparation à la vie professionnelle.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que la formation facilitait l'accès à un emploi qualifié. Cela montre qu'un jeune doit commencer par développer ses compétences.",
      "Ensuite, l'expérience professionnelle joue également un rôle essentiel dans la recherche d'un emploi. Autrement dit, elle contribue à mettre ses connaissances en pratique et à mieux comprendre les besoins des employeurs.",
      "Prenons mon propre exemple. Lorsque je travaillais dans les ressources humaines, j'ai constaté que les employeurs recherchaient des personnes capables d'apprendre et de s'adapter. Cet exemple prouve qu'un stage, un emploi temporaire ou une activité de bénévolat peut être utile.",
      "Toutefois, j'aimerais ajouter un dernier point concernant la formation. Même si la formation offre de réels avantages, elle ne constitue pas le seul facteur à prendre en compte. En effet, la formation peut s'avérer particulièrement bénéfique pour les jeunes qui font preuve de motivation et développent leur capacité d'adaptation.",
      "Prenons le cas de mon ami Paul. Grâce à son excellente capacité d'apprentissage et à ses solides compétences techniques, il s'adapte rapidement aux nouvelles méthodes de travail. On voit donc qu'un jeune doit continuer à apprendre, acquérir de l'expérience et rester motivé.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'probleme-mondial',category:'categorie-societe',title:"Quel problème mondial est le plus important aujourd’hui ? Pourquoi ?",p:[
      "Si je comprends bien, il s'agit de choisir le problème mondial qui me paraît le plus important aujourd'hui.",
      "Il serait intéressant de réfléchir à cette question. Si je devais en retenir quelques-unes, je choisirais la protection de l'environnement. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, la protection de l'environnement constitue un véritable atout, car cela permet de préserver les ressources naturelles. En effet, cela favorise également un avenir plus durable pour les générations futures.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que la protection de l'environnement était une priorité. Cela montre que ce problème concerne toute la société.",
      "Ensuite, les comportements responsables jouent également un rôle essentiel dans la protection de l'environnement. Autrement dit, ils contribuent à réduire le gaspillage, la pollution et la consommation d'énergie.",
      "Prenons l'exemple de mon fils. À l'école, il apprend à recycler et à économiser l'énergie. Cet exemple prouve que chacun peut agir dès le plus jeune âge.",
      "Toutefois, j'aimerais ajouter un dernier point concernant les actions collectives. Même si les gestes individuels offrent de réels avantages, cela ne signifie pas que les actions des pouvoirs publics et des entreprises soient moins importantes. En effet, les actions collectives peuvent également apporter de nombreux bénéfices.",
      "Prenons le cas d'une famille qui trie ses déchets alors que les entreprises utilisent encore trop d'emballages. On voit donc que la protection de l'environnement exige la participation de tous.",
      "En définitive, ce choix correspond pleinement à mes centres d'intérêt, à mon expérience et à mes objectifs. Il s'agit avant tout de poursuivre un projet qui me permette de continuer à apprendre et à progresser."
    ]},
    {id:'animaux-disparition',category:'categorie-societe',title:"Selon vous, doit-on protéger tous les animaux en voie de disparition ? Pourquoi ?",p:[
      "Si je comprends bien, il s'agit de savoir s'il faut protéger tous les animaux en voie de disparition.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que la protection des animaux en voie de disparition présente de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, la protection des espèces menacées constitue un véritable atout, car cela permet de préserver la biodiversité et l'équilibre de la nature. En effet, cela favorise également la protection des ressources pour les générations futures.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que chaque espèce jouait un rôle dans son environnement. Cela montre que même les animaux moins connus peuvent être importants pour la nature.",
      "Ensuite, l'éducation joue également un rôle essentiel dans la protection des animaux. Autrement dit, elle contribue à sensibiliser les enfants et à développer des comportements plus responsables.",
      "Prenons l'exemple de mon fils. À l'école, il apprend que certaines espèces sont menacées et que chaque animal joue un rôle dans la nature. Cet exemple prouve que la sensibilisation peut encourager la protection des animaux dès le plus jeune âge.",
      "Toutefois, j'aimerais ajouter un dernier point concernant la protection des animaux en voie de disparition. Même si la protection des animaux en voie de disparition offre de réels avantages, elle ne constitue pas le seul facteur à prendre en compte. En effet, la protection des animaux en voie de disparition peut s'avérer particulièrement bénéfique lorsque les habitats naturels sont également préservés.",
      "Prenons le cas de certaines espèces dont l'habitat disparaît progressivement. Les efforts individuels restent limités sans l'action des pouvoirs publics, des entreprises et des associations. On voit donc que protéger tous les animaux exige aussi des mesures collectives adaptées.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'metier-professeur-difficile',category:'categorie-travail',title:"Pour quelles raisons le métier de professeur peut-il paraître difficile ou impressionnant ?",p:[
      "Si je comprends bien, il s'agit de savoir pourquoi le métier de professeur peut paraître difficile ou impressionnant.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que le métier de professeur présente de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, la transmission des connaissances constitue un véritable atout, car cela permet de préparer les élèves à leur avenir. En effet, cela favorise également leur développement personnel et leur capacité à apprendre.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que les professeurs jouaient un rôle essentiel dans l'éducation. Cela montre que leur métier comporte une grande responsabilité.",
      "Ensuite, la capacité d'adaptation joue également un rôle essentiel dans l'enseignement. Autrement dit, elle contribue à adapter les explications aux besoins et au niveau de chaque élève.",
      "Prenons l'exemple de mon amie Sophie. Elle travaille comme professeure dans une école primaire à Vancouver. Elle prépare ses cours, adapte ses explications et communique régulièrement avec les parents. Cet exemple prouve que ce métier demande des compétences, de la patience et un travail régulier.",
      "Toutefois, j'aimerais ajouter un dernier point concernant le métier de professeur. Même si le métier de professeur offre de réels avantages, il ne constitue pas le seul facteur à prendre en compte. En effet, le métier de professeur peut s'avérer particulièrement bénéfique pour les personnes qui aiment transmettre leurs connaissances et voir les enfants progresser.",
      "Prenons encore l'exemple de mon amie Sophie. Même si elle doit gérer la classe et assumer de nombreuses responsabilités, elle est heureuse de voir ses élèves progresser. On voit donc que ce métier peut être à la fois difficile et très satisfaisant.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]},
    {id:'age-raisonnable-travailler',category:'categorie-travail',title:"À votre avis, jusqu’à quel âge est-il raisonnable de travailler ? Expliquez.",p:[
      "Si je comprends bien, il s'agit de savoir jusqu'à quel âge il est raisonnable de travailler.",
      "Il serait intéressant de s'interroger sur les différents aspects de cette question. Bien que le fait de continuer à travailler présente de nombreux avantages, il convient également de prendre en considération d'autres facteurs. J'aimerais développer trois arguments qui expliquent mon point de vue.",
      "Pour commencer, le fait de continuer à travailler constitue un véritable atout, car cela permet de rester actif et de conserver des relations sociales. En effet, cela favorise également la transmission de l'expérience aux personnes plus jeunes.",
      "Par exemple, j'ai entendu parler d'un sujet abordé dans Quotidien, une émission très connue en France, où l'on indiquait qu'environ 80 % des personnes interrogées considéraient que rester actif contribuait à leur bien-être. Cela montre que le travail peut encore apporter des bénéfices avec l'âge.",
      "Ensuite, l'expérience joue également un rôle essentiel dans la vie professionnelle. Autrement dit, elle contribue à mieux gérer les situations complexes et à transmettre des connaissances utiles.",
      "Prenons l'exemple de mon père. Après de nombreuses années de travail, il souhaite rester actif, mais il préfère réduire progressivement son rythme. Cet exemple prouve qu'une transition progressive peut permettre de continuer à travailler dans de bonnes conditions.",
      "Toutefois, j'aimerais ajouter un dernier point concernant le fait de continuer à travailler. Même si le fait de continuer à travailler offre de réels avantages, il ne constitue pas le seul facteur à prendre en compte. En effet, le fait de continuer à travailler peut s'avérer particulièrement bénéfique pour les personnes dont la santé et les conditions de travail le permettent.",
      "Prenons encore l'exemple de mon père. Il tient compte de son état de santé et consulte son médecin lorsque cela est nécessaire. On voit donc qu'il n'existe pas un âge idéal pour tout le monde : la décision dépend de la santé, de la pénibilité du métier et du choix personnel.",
      "En définitive, cette question ne peut être abordée sous un seul angle. Il s'agit avant tout de prendre en considération l'ensemble des facteurs avant de se faire une opinion."
    ]}
  ];

  const container=document.querySelector('#t3-oral .module-child-sections');
  questions.forEach(question=>{
    if(document.getElementById(question.id)||!container)return;
    const section=document.createElement('section');section.id=question.id;section.className='section t3-question t3-batch-question';
    section.innerHTML=`<details class="t3-details"><summary>${question.title}</summary>${question.p.map(text=>`<p>${text}</p>`).join('')}</details>`;
    container.appendChild(section);
    const nav=document.querySelector(`.nav-category > a[href="#${question.category}"]`)?.parentElement;
    if(nav){let list=nav.querySelector(':scope > ul');if(!list){list=document.createElement('ul');nav.appendChild(list);}const li=document.createElement('li');li.innerHTML=`<a href="#${question.id}">${question.title}</a>`;list.appendChild(li);}
  });

  const variants={
    'integration-jeune':"Il est plus facile de partir vivre dans un pays étranger quand on est jeune. Êtes-vous d'accord avec cette affirmation ?",
    'salaire':"La chose la plus importante dans un travail, c'est le salaire. Qu'en pensez-vous ?",
    'education-maison':"Certains parents favorisent l'éducation à la maison. Qu'en pensez-vous ?",
    'telephone-ecole':"Que pensez-vous de l'utilisation du téléphone portable par les élèves dans les écoles ?",
    'travailler-etudier':"Pensez-vous qu'il est possible de travailler et de fréquenter les cours en même temps ?",
    'urbain-rural':"Est-ce agréable pour les personnes âgées de vivre en milieu urbain ou en milieu rural ? Quelle est votre opinion ?",
    'livres':"Selon vous, lire est-il une activité inutile ? Pourquoi ?"
  };
  window.applyT3QuestionVariants=()=>Object.entries(variants).forEach(([id,text])=>{const details=document.querySelector(`#${id} > .t3-details`);if(!details||details.querySelector('.question-variant'))return;const note=document.createElement('p');note.className='question-variant';note.innerHTML=`<strong>Autre formulation :</strong> ${text}`;details.querySelector('summary')?.after(note);});
  window.applyT3QuestionVariants();
})();
